import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { Menu } from '@headlessui/react';
import { BellIcon, UserCircleIcon } from '@heroicons/react/24/outline';
import { useSocket } from '../contexts/SocketContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const { alerts, setAlerts } = useSocket();
  const navigate = useNavigate();

  const unreadAlerts = alerts.length;

  return (
    <nav className="bg-white shadow-lg">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16">
          <div className="flex items-center">
            <Link to="/" className="text-xl font-bold text-green-600">
              AgriVend
            </Link>
          </div>
          
          <div className="flex items-center space-x-4">
            {/* Notifications */}
            <Menu as="div" className="relative">
              <Menu.Button className="p-2 rounded-full hover:bg-gray-100 relative">
                <BellIcon className="h-6 w-6 text-gray-600" />
                {unreadAlerts > 0 && (
                  <span className="absolute top-0 right-0 inline-flex items-center justify-center px-2 py-1 text-xs font-bold leading-none text-white transform translate-x-1/2 -translate-y-1/2 bg-red-600 rounded-full">
                    {unreadAlerts}
                  </span>
                )}
              </Menu.Button>
              <Menu.Items className="absolute right-0 mt-2 w-80 bg-white rounded-md shadow-lg py-1 z-10">
                <div className="px-4 py-2 border-b">
                  <h3 className="text-sm font-semibold">Notifications</h3>
                </div>
                <div className="max-h-96 overflow-y-auto">
                  {alerts.length === 0 ? (
                    <p className="px-4 py-3 text-sm text-gray-500">No new alerts</p>
                  ) : (
                    alerts.map((alert, index) => (
                      <div key={index} className="px-4 py-3 hover:bg-gray-50 border-b">
                        <p className="text-sm font-medium">
                          {alert.type === 'LOW_STOCK' && `⚠️ Low Stock: ${alert.container}`}
                          {alert.type === 'LOW_BATTERY' && `🔋 Low Battery: ${alert.percentage}%`}
                          {alert.type === 'NEW_RETURN' && `📦 New Return: ${alert.data?.return_id}`}
                          {alert.type === 'NEW_MESSAGE' && `💬 New Message`}
                          {alert.type === 'NEW_RATING' && `⭐ New Rating`}
                        </p>
                        <p className="text-xs text-gray-500 mt-1">
                          {alert.type === 'LOW_STOCK' && `${alert.level}kg remaining`}
                        </p>
                      </div>
                    ))
                  )}
                </div>
                <div className="px-4 py-2 border-t">
                  <button
                    onClick={() => setAlerts([])}
                    className="text-sm text-green-600 hover:text-green-800"
                  >
                    Clear all
                  </button>
                </div>
              </Menu.Items>
            </Menu>

            {/* User menu */}
            <Menu as="div" className="relative">
              <Menu.Button className="flex items-center space-x-2 p-2 rounded-full hover:bg-gray-100">
                <UserCircleIcon className="h-8 w-8 text-gray-600" />
                <span className="text-sm font-medium text-gray-700">
                  {user?.first_name} {user?.last_name}
                </span>
              </Menu.Button>
              <Menu.Items className="absolute right-0 mt-2 w-48 bg-white rounded-md shadow-lg py-1 z-10">
                <Menu.Item>
                  {({ active }) => (
                    <Link
                      to={user?.role === 'admin' ? '/admin/profile' : '/customer/profile'}
                      className={`block px-4 py-2 text-sm text-gray-700 ${active ? 'bg-gray-100' : ''}`}
                    >
                      Profile
                    </Link>
                  )}
                </Menu.Item>
                <Menu.Item>
                  {({ active }) => (
                    <button
                      onClick={logout}
                      className={`block w-full text-left px-4 py-2 text-sm text-gray-700 ${active ? 'bg-gray-100' : ''}`}
                    >
                      Logout
                    </button>
                  )}
                </Menu.Item>
              </Menu.Items>
            </Menu>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
